const items = $input.all();
const results = [];

for (const item of items) {
  const html = item.json.html || item.json.textHtml || item.json.text || '';
  const from = (item.json.from || '').toLowerCase();

  let source = 'inconnu';
  if (from.includes('centris')) source = 'centris';
  else if (from.includes('duproprio')) source = 'duproprio';
  else if (from.includes('realtor')) source = 'realtor';

  results.push({
    json: {
      source: source,
      emailSubject: item.json.subject || 'Alerte immobilière',
      emailDate: item.json.date || new Date().toISOString(),
      emailBody: html.substring(0, 15000),
    }
  });
}

return results;

const emailData = $('Code1').first().json;
const sheetRows = $('Get row(s) in sheet').all();

let historyContext = 'Aucune donnée historique disponible.';

if (sheetRows.length > 0) {
  const recentProps = sheetRows
    .slice(-30)
    .map(row => {
      const r = row.json;
      return `${r.date} | ${r.source} | ${r.adresse} | ${r.prix}$ | ${r.type} | GRM:${r.grm} | Score:${r.score}`;
    })
    .join('\n');

  historyContext = `Voici les ${Math.min(sheetRows.length, 30)} dernières propriétés analysées :\n${recentProps}`;
}

return [{
  json: {
    ...emailData,
    historyContext: historyContext,
    totalHistoryCount: sheetRows.length
  }
}];

const emailData = $input.first().json;

const systemPrompt = `Tu es un analyste immobilier spécialisé dans le marché des multiplex à Montréal. Tu travailles pour un investisseur qui cherche activement à acheter.

CRITÈRES DE L'ACHETEUR :
- Budget : 700 000$ à 1 000 000$
- Types recherchés : Triplex, Quadruplex, Quintuplex uniquement
- Ignore les duplex, plex (6+), condos, maisons
- Localisation : Montréal (île) - tous les arrondissements
- Objectif : investissement locatif (habiter un logement, louer les autres)
- Priorités : bon rendement locatif, quartier en demande, état acceptable
- Mise de fonds prévue : 10% (propriétaire-occupant, 3-4 logements)

ANALYSE DE PREMIER NIVEAU (toujours) :
Pour chaque propriété pertinente, fournis :
- adresse (string)
- prix (number)
- type : triplex|quadruplex|quintuplex
- logements (number)
- revenus_bruts (number ou null)
- lien (string ou null)
- grm (number ou null) : prix / revenus bruts annuels TOUTES unités incluses. Impute un loyer marché pour le logement occupé. GRM sous 14 = excellent, 14-17 = acceptable, au-dessus de 17 = alerte.
- cap_rate (number ou null) : NOI / prix. NOI = revenus bruts x 0.65 (hypothèse 35% dépenses)
- dscr (number ou null) : NOI / paiements hypothécaires annuels. Hypothèses : taux 5.75%, amortissement 25 ans, mise de fonds 10%. DSCR sous 1.0 = cash flow négatif.
- cout_net_habiter (number ou null) : paiement hypothécaire mensuel + taxes estimées/12 - revenus locatifs mensuels des autres unités
- score (number 1-10)
- commentaire (string, 2-3 phrases)

ANALYSE DE DEUXIÈME NIVEAU (seulement quand les revenus bruts sont disponibles) :
Quand les revenus sont déclarés, calcule toutes les métriques financières. Indique clairement quand tu estimes vs quand tu utilises des données déclarées. Marque les estimations avec [estimé].

QUARTIERS À PRIORISER (score plus élevé) :
- Rosemont, Villeray, Ahuntsic : établis, forte demande
- Plateau, Petite-Patrie : premium, excellent rendement
- NDG (secteur Monkland), Verdun, LaSalle : quartiers familiaux en demande, bonne appréciation
- Mercier : potentiel d'appréciation

QUARTIERS À ÉVALUER AVEC PRUDENCE :
- Hochelaga-Maisonneuve : potentiel d'appréciation souvent annoncé mais lent à se concrétiser. Scorer de façon conservatrice, le rendement locatif doit compenser le risque d'appréciation incertain.

SIGNAUX D'ALERTE :
- GRM supérieur à 17
- DSCR sous 1.0 au taux stressé
- Prix anormalement bas
- Aucun revenu déclaré
- Éloigné du transport en commun
- Écart revenus déclarés vs loyers du marché

FORMAT DE RÉPONSE :
Réponds UNIQUEMENT avec un JSON valide, sans texte avant ni après, sans backticks markdown.
Structure :
{
  "resume": "X propriétés pertinentes sur Y reçues",
  "proprietes": [
    {
      "adresse": "",
      "prix": 0,
      "type": "",
      "logements": 0,
      "revenus_bruts": null,
      "lien": null,
      "grm": null,
      "cap_rate": null,
      "dscr": null,
      "cout_net_habiter": null,
      "score": 0,
      "commentaire": "",
      "comparaison_historique": ""
    }
  ],
  "ignorees": [
    {
      "adresse": "",
      "raison": ""
    }
  ]
}`;

const userMessage = `COMPARAISON HISTORIQUE :
Voici les propriétés déjà analysées. Compare les nouveaux listings à cet historique.

${emailData.historyContext}

Total en base : ${emailData.totalHistoryCount}

---

Source : ${emailData.source}
Sujet : ${emailData.emailSubject}
Date : ${emailData.emailDate}

Contenu :
${emailData.emailBody}`;

return [{
  json: {
    requestBody: {
      model: "claude-sonnet-4-20250514",
      max_tokens: 4000,
      system: [
        {
          type: "text",
          text: systemPrompt,
          cache_control: { type: "ephemeral" }
        }
      ],
      messages: [
        {
          role: "user",
          content: userMessage
        }
      ]
    }
  }
}];

const response = $input.first().json;
const source = $('Code2').first().json.source;
const today = new Date().toISOString().split('T')[0];

// Extraire le texte de la réponse Claude
let rawText = '';
if (response.content && Array.isArray(response.content)) {
  rawText = response.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('');
}

// Parser le JSON
let data;
try {
  // Nettoyer le texte au cas où Claude ajoute des backticks
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  data = JSON.parse(cleaned);
} catch (e) {
  // Si le parsing échoue, on envoie quand même un email avec le texte brut
  return [{
    json: {
      sheetRows: [],
      hasHighScore: true, // envoyer quand même pour debug
      emailSubject: `Veille Immobilière - ${today} (parsing error)`,
      emailHtml: `<pre>${rawText}</pre>`
    }
  }];
}

// Préparer les lignes pour Google Sheet
const sheetRows = (data.proprietes || []).map(p => ({
  date: today,
  source: source,
  adresse: p.adresse || '',
  prix: p.prix || '',
  type: p.type || '',
  logements: p.logements || '',
  revenus_bruts: p.revenus_bruts || '',
  grm: p.grm || '',
  cap_rate: p.cap_rate || '',
  dscr: p.dscr || '',
  score: p.score || 0,
  commentaire: p.commentaire || '',
  lien: p.lien || ''
}));

// Vérifier s'il y a au moins une propriété avec score >= 7
const highScoreProps = (data.proprietes || []).filter(p => p.score >= 7);
const hasHighScore = highScoreProps.length > 0;

// Construire l'email HTML
const propsHtml = (data.proprietes || []).map(p => {
  const scoreColor = p.score >= 7 ? '#2f855a' : p.score >= 5 ? '#b7791f' : '#c53030';
  const financials = p.revenus_bruts ? `
    <tr><td style="padding:4px 8px;color:#666;">Revenus bruts</td><td style="padding:4px 8px;font-weight:bold;">${p.revenus_bruts?.toLocaleString('fr-CA')}$/an</td></tr>
    <tr><td style="padding:4px 8px;color:#666;">GRM</td><td style="padding:4px 8px;font-weight:bold;">${p.grm || 'N/D'}</td></tr>
    <tr><td style="padding:4px 8px;color:#666;">Cap rate</td><td style="padding:4px 8px;font-weight:bold;">${p.cap_rate ? (p.cap_rate * 100).toFixed(1) + '%' : 'N/D'}</td></tr>
    <tr><td style="padding:4px 8px;color:#666;">DSCR (stressé 5.75%)</td><td style="padding:4px 8px;font-weight:bold;">${p.dscr || 'N/D'}</td></tr>
    <tr><td style="padding:4px 8px;color:#666;">Coût net habiter</td><td style="padding:4px 8px;font-weight:bold;">${p.cout_net_habiter ? p.cout_net_habiter.toLocaleString('fr-CA') + '$/mois' : 'N/D'}</td></tr>
  ` : '<tr><td style="padding:4px 8px;color:#999;" colspan="2">Revenus non déclarés - analyse financière impossible</td></tr>';

  return `
  <div style="border:1px solid #e2e8f0;border-radius:8px;padding:16px;margin-bottom:16px;${p.score >= 7 ? 'border-left:4px solid #2f855a;' : ''}">
    <div style="display:flex;justify-content:space-between;align-items:center;">
      <h3 style="margin:0;color:#1a365d;">${p.adresse}</h3>
      <span style="background:${scoreColor};color:white;padding:4px 12px;border-radius:12px;font-weight:bold;font-size:14px;">${p.score}/10</span>
    </div>
    <p style="color:#4a5568;margin:8px 0;">${p.type} | ${p.logements} logements | <strong>${p.prix?.toLocaleString('fr-CA')}$</strong></p>
    <table style="width:100%;border-collapse:collapse;margin:8px 0;">
      ${financials}
    </table>
    <p style="color:#333;margin:8px 0;">${p.commentaire}</p>
    ${p.comparaison_historique ? `<p style="color:#2b6cb0;font-style:italic;margin:4px 0;">📊 ${p.comparaison_historique}</p>` : ''}
    ${p.lien ? `<a href="${p.lien}" style="color:#2b6cb0;">Voir sur ${source}</a>` : ''}
  </div>`;
}).join('');

const ignoreesHtml = (data.ignorees || []).length > 0
  ? `<div style="margin-top:20px;padding:12px;background:#f7fafc;border-radius:8px;">
      <h4 style="color:#666;margin:0 0 8px 0;">Propriétés ignorées</h4>
      ${data.ignorees.map(i => `<p style="color:#999;margin:2px 0;">• ${i.adresse} — ${i.raison}</p>`).join('')}
    </div>`
  : '';

const emailHtml = `
<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;">
  <h2 style="color:#1a365d;border-bottom:2px solid #2b6cb0;padding-bottom:8px;">
    Veille Immobilière - Multiplex Montréal
  </h2>
  <p style="color:#666;font-size:13px;">
    Source : ${source} | Critères : Triplex à Quintuplex | Île de Montréal | 700k$-1M$ | ${today}
  </p>
  <p style="font-size:15px;color:#333;"><strong>${data.resume}</strong></p>
  ${propsHtml}
  ${ignoreesHtml}
  <hr style="margin-top:30px;border:none;border-top:1px solid #ddd;">
  <p style="color:#999;font-size:11px;">Généré par n8n + Claude | Propriétés en base : ${$('Code2').first().json.totalHistoryCount || 0}</p>
</div>`;

return [{
  json: {
    sheetRows: sheetRows,
    hasHighScore: hasHighScore,
    highScoreCount: highScoreProps.length,
    totalCount: (data.proprietes || []).length,
    emailSubject: `🏠 Veille Immobilière - ${highScoreProps.length} opportunité(s) - ${today}`,
    emailHtml: emailHtml
  }
}];
